const input = $input.first().json;

const missing = [];

if (!input.execution_id) {
  missing.push("execution_id");
}

if (!input.payload) {
  missing.push("payload");
}

if (!input.technical_design) {
  missing.push("technical_design");
}

if (!input.technical_design?.project_structure) {
  missing.push("technical_design.project_structure");
}

if (!input.technical_design?.api_endpoints) {
  missing.push("technical_design.api_endpoints");
}

if (missing.length > 0) {
  return [
    {
      json: {
        ...input,
        wf03_validation: {
          passed: false,
          missing_fields: missing,
          reason: "Technical design is incomplete"
        },
        current_workflow: "WF03",
        next_workflow: "WF08",
        status: "BLOCKED"
      }
    }
  ];
}

return [
  {
    json: {
      ...input,
      wf03_validation: {
        passed: true,
        missing_fields: []
      }
    }
  }
];

const input = $input.first().json;

let raw =
  input.output ||
  input.text ||
  input.response ||
  input.content ||
  input.message ||
  input.data;

if (!raw) {
  return [
    {
      json: {
        ...input,
        wf03_result: {
          tdd_test_design: {
            test_strategy_summary: "No AI output found",
            unit_tests: [],
            integration_tests: [],
            api_tests: [],
            edge_cases: [],
            failure_scenarios: [],
            acceptance_coverage_matrix: [],
            pytest_files: [],
            fixtures: [],
            mocking_strategy: [],
            test_execution_commands: [],
            quality_risks: []
          },
          quality_gate: {
            passed: false,
            blocking_issues: ["No AI output found"],
            recommendation: "HUMAN_REVIEW"
          },
          next_workflow: "WF08"
        }
      }
    }
  ];
}

if (typeof raw !== "string") {
  raw = JSON.stringify(raw);
}

raw = raw
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

raw = raw.replace(/\/\/.*$/gm, "");

const firstBrace = raw.indexOf("{");
const lastBrace = raw.lastIndexOf("}");

if (firstBrace === -1 || lastBrace === -1) {
  return [
    {
      json: {
        ...input,
        wf03_result: {
          tdd_test_design: {
            test_strategy_summary: "Invalid AI JSON",
            unit_tests: [],
            integration_tests: [],
            api_tests: [],
            edge_cases: [],
            failure_scenarios: [],
            acceptance_coverage_matrix: [],
            pytest_files: [],
            fixtures: [],
            mocking_strategy: [],
            test_execution_commands: [],
            quality_risks: []
          },
          quality_gate: {
            passed: false,
            blocking_issues: ["Invalid AI JSON"],
            recommendation: "HUMAN_REVIEW"
          },
          next_workflow: "WF08"
        }
      }
    }
  ];
}

const jsonString =
  raw.slice(firstBrace, lastBrace + 1);

let parsed;

try {
  parsed = JSON.parse(jsonString);
}
catch (error) {
  return [
    {
      json: {
        ...input,
        wf03_result: {
          tdd_test_design: {
            test_strategy_summary: "JSON parse failed",
            unit_tests: [],
            integration_tests: [],
            api_tests: [],
            edge_cases: [],
            failure_scenarios: [],
            acceptance_coverage_matrix: [],
            pytest_files: [],
            fixtures: [],
            mocking_strategy: [],
            test_execution_commands: [],
            quality_risks: []
          },
          quality_gate: {
            passed: false,
            blocking_issues: [error.message],
            recommendation: "HUMAN_REVIEW"
          },
          next_workflow: "WF08"
        }
      }
    }
  ];
}

return [
  {
    json: {
      ...input,
      wf03_result: parsed
    }
  }
];

const input = $input.first().json;

const original =
  $('01 - Extract WF02 Payload').item.json;

const payload =
  original.payload;

const result =
  input.wf03_result;

const nextWorkflow =
  result.quality_gate?.passed === true
    ? "WF04A"
    : "WF08";

const updatedPayload = {
  ...payload,

  factory: {
    ...payload.factory,
    current_workflow: "WF03",
    next_workflow: nextWorkflow,
    status:
      nextWorkflow === "WF04A"
        ? "RUNNING"
        : "BLOCKED",

    workflow_history: [
      ...(payload.factory.workflow_history || []),
      "WF03"
    ]
  },

  tdd_test_design: result.tdd_test_design,

  quality_gate: result.quality_gate,

  artifacts: [
    ...(payload.artifacts || []),

    {
      workflow: "WF03",
      type: "tdd_test_design",
      name: "tdd_test_design.json",
      content: result.tdd_test_design
    }
  ]
};

return [
  {
    json: {
      execution_id: original.execution_id,
      payload: updatedPayload,
      current_workflow: "WF03",
      next_workflow: nextWorkflow,
      status: updatedPayload.factory.status,
      quality_gate: result.quality_gate
    }
  }
];
